export default {
  name: 'SideCart',
  props: ['cartShow', 'cart', 'total'],
  emits: ['cartClose'],
  data() {
    return {
        items: []
    }
  },
  computed: {
    cartTotal() {
        if (!Object.keys(this.cart).length) {
            return 0
        } else {
            return this.total * 590
        }
    }
  },
  mounted() {
    const data = require('../items.json')
    this.items = data
    console.log(data)
  }
}
